CREATE EXTENSION IF NOT EXISTS vector;
CREATE TABLE "User" ("id" TEXT PRIMARY KEY, "email" TEXT NOT NULL UNIQUE, "name" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Project" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "category" TEXT NOT NULL, "icp" TEXT, "description" TEXT, "ownerId" TEXT REFERENCES "User"("id"), "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Source" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "type" TEXT NOT NULL, "name" TEXT NOT NULL, "query" TEXT, "url" TEXT, "config" JSONB, "status" TEXT NOT NULL DEFAULT 'active', "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "RawRecord" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "source" TEXT NOT NULL, "sourceUrl" TEXT, "author" TEXT, "date" TIMESTAMP, "title" TEXT, "body" TEXT NOT NULL, "product" TEXT, "engagement" INTEGER, "rawPayload" JSONB, "ingestedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ProcessedRecord" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "rawRecordId" TEXT NOT NULL UNIQUE REFERENCES "RawRecord"("id") ON DELETE CASCADE, "cleanedText" TEXT NOT NULL, "language" TEXT, "entities" JSONB, "productNames" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "competitorNames" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "workflowVerbs" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "toolStack" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "complaintPhrases" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "fingerprint" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Classification" ("id" TEXT PRIMARY KEY, "rawRecordId" TEXT NOT NULL REFERENCES "RawRecord"("id") ON DELETE CASCADE, "signalType" TEXT NOT NULL, "painCategory" TEXT NOT NULL, "emotionalIntensity" INTEGER NOT NULL, "urgency" INTEGER NOT NULL, "persona" TEXT, "productArea" TEXT, "workflowStep" TEXT, "willingnessToPaySignal" BOOLEAN NOT NULL DEFAULT false, "workaroundPresent" BOOLEAN NOT NULL DEFAULT false, "competitorsMentioned" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "toolsMentioned" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "summary" TEXT NOT NULL, "quotableLanguage" TEXT, "confidence" DOUBLE PRECISION NOT NULL, "why" TEXT, "promptLog" JSONB, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Embedding" ("id" TEXT PRIMARY KEY, "rawRecordId" TEXT NOT NULL REFERENCES "RawRecord"("id") ON DELETE CASCADE, "provider" TEXT NOT NULL, "model" TEXT NOT NULL, "dimensions" INTEGER NOT NULL, "vector" vector, "vectorJson" JSONB, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Cluster" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "name" TEXT NOT NULL, "description" TEXT NOT NULL, "recordIds" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "representativeQuotes" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "sourceMix" JSONB NOT NULL, "personas" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "productsMentioned" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "frequency" INTEGER NOT NULL, "emotionalIntensity" DOUBLE PRECISION NOT NULL, "opportunityScore" INTEGER NOT NULL, "evidenceStrength" INTEGER NOT NULL, "recommendedProductWedge" TEXT NOT NULL, "recommendedPmmAngle" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Opportunity" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "clusterId" TEXT REFERENCES "Cluster"("id") ON DELETE SET NULL, "title" TEXT NOT NULL, "targetUser" TEXT NOT NULL, "problemStatement" TEXT NOT NULL, "existingAlternatives" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "whyCurrentToolsFail" TEXT NOT NULL, "mvpScope" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "willingnessToPayHypothesis" TEXT NOT NULL, "pricingHypothesis" TEXT NOT NULL, "distributionChannels" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "validationPlan" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "risks" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "moatPossibilities" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "whyNow" TEXT NOT NULL, "consultingRelevance" TEXT NOT NULL, "buildRecommendation" TEXT NOT NULL, "score" INTEGER NOT NULL, "evidenceRecordIds" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Report" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "type" TEXT NOT NULL, "title" TEXT NOT NULL, "markdown" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'ready', "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "SavedInsight" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "rawRecordId" TEXT, "clusterId" TEXT, "opportunityId" TEXT, "note" TEXT, "useful" BOOLEAN, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Tag" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "color" TEXT);
CREATE TABLE "_SavedInsightToTag" ("A" TEXT NOT NULL REFERENCES "SavedInsight"("id") ON DELETE CASCADE, "B" TEXT NOT NULL REFERENCES "Tag"("id") ON DELETE CASCADE, PRIMARY KEY ("A", "B"));
CREATE TABLE "Run" ("id" TEXT PRIMARY KEY, "projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE, "type" TEXT NOT NULL, "status" TEXT NOT NULL, "startedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "finishedAt" TIMESTAMP, "stats" JSONB, "error" TEXT);
CREATE TABLE "Export" ("id" TEXT PRIMARY KEY, "reportId" TEXT NOT NULL REFERENCES "Report"("id") ON DELETE CASCADE, "format" TEXT NOT NULL, "path" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "RawRecord_projectId_idx" ON "RawRecord"("projectId");
CREATE INDEX "Classification_signalType_idx" ON "Classification"("signalType");
CREATE INDEX "Cluster_projectId_score_idx" ON "Cluster"("projectId", "opportunityScore");
